import { Component, h, Prop, Element, Listen } from '@stencil/core';

@Component({
  tag: 'wdpr-tile-row',
  shadow: true,
})
export class WdprTileRow {
  @Element() el: HTMLWdprTileRowElement;

  @Prop({ reflect: true, mutable: true }) columns: number = 1;
  @Prop({ reflect: true, mutable: true }) cellColumns: number = 1;

  componentDidLoad() {
    this._propagateToSlotElements();
  }

  @Listen('slotchange')
  onSlotChange() {
    this._propagateToSlotElements();
  }

  private _propagateToSlotElements = () => {
    const slot = this.el.shadowRoot.querySelector('slot');

    if (slot) {
      slot.assignedElements().forEach((el: HTMLWdprTileRowElement) => {
        el.cellColumns = this.cellColumns;
      });
    }
  };

  render() {
    return (
      <div class={rowClass} style={{ gridTemplateColumns: `repeat(${this.columns}, 1fr)` }}>
        <slot></slot>
      </div>
    );
  }
}

const rowClass = 'grid gap-150 mb-100';
